use std::io::{self, Write}; 

struct User {
    id: u32,
    username: String,
    is_active: bool,
}

fn print_user_status(user: &User) -> io::Result<()> {
    let status = if user.is_active {
        "Success: Active User"
    } else {
        "Warning: Inactive Account"
    };

    let reset = "x1b[0m";
    let color_code = if user.is_active {
        "x1b[32m" // Green for success
    } else {
        "x1b[33m" // Yellow for warning
    };

    print!("{}{}{}n", color_code, status, reset);
    io::stdout().flush()
}

fn main() -> io::Result<()> {
    let user1 = User { id: 101, username: String::from("api_user"), is_active: true };
    print_user_status(&user1)?;

    let user2 = User {
        id: 102,
        username: String::from("guest"),
        is_active: false,
    };
    print_user_status(&user2)?;

    Ok(())
}

use std::time::Duration;

struct PinState {
    is_active: bool,
    last_read_value: u32,
}

impl PinState {
    fn new(initial_value: u32) -> Self {
        PinState { 
            is_active: false,
            last_read_value: initial_value,
        }
    }

    fn poll_until_high(&mut self, timeout: Duration) -> Result<(), &'static str> {
        let start = std::time::Instant::now();
        while start.elapsed() < timeout {
            let simulated_read = self.last_read_value;
            if (simulated_read & 0x1) != 0 {
                self.is_active = true;
                return Ok(()) 
            }
            std::thread::sleep(Duration::from_millis(5));
        }
        Err("Timeout waiting for signal transition")
    }

    fn check_bit(&mut self, mask: u32) -> bool {
        let current_value = self.last_read_value;
        if (current_value & mask) != 0 {
            self.is_active = true;
            true
        } else {
            self.is_active = false;
            false
        }
    }
}

fn main() {
    let mut gpio_input = PinState::new(0x0); 
    gpio_input.last_read_value = 0b10;

    println!("Checking status register bit...");
    if gpio_input.check_bit(0b1) {
        println!("  Status OK: Bit is asserted.");
    } else {
        println!("  Status WARNING: Bit clear.");
    }

    gpio_input.last_read_value = 0b1;
    match gpio_input.poll_until_high(Duration::from_millis(50)) {
        Ok(_) => println!("  GPIO Poll Success: Pin went high."),
        Err(e) => println!("  GPIO Poll Error: {}", e),
    }
}

use std::time::{Duration, Instant};

struct HardwareMonitor {
    threshold: u32,
}

impl HardwareMonitor {
    fn new(threshold: u32) -> Self {
        HardwareMonitor { threshold }
    }

    fn read_and_display(&self) {
        let simulated_value = (rand::random::<u32>() % 100) + 50;

        if simulated_value > self.threshold {
            println!("x1b[31mCPU Load High: {}x1b[0m", simulated_value);
        } else {
            println!("x1b[32mCPU Load Normal: {}x1b[0m", simulated_value);
        }
    }
}

fn main() {
    let monitor = HardwareMonitor::new(75);
    println!("Starting system status stream. Press Ctrl+C to exit.");

    loop {
        monitor.read_and_display();
        std::thread::sleep(Duration::from_millis(300));
    }
}

use std::thread;
use std::time::Duration;

struct Webhook {
    url: String,
    payload: String,
}

impl Webhook {
    fn dispatch(&self) -> Result<(), &'static str> {
        if self.url.contains("fail") {
            return Err("Connection refused");
        }
        println!("Successfully sent data to {}", self.url);
        Ok(())
    }
}

fn main() {
    let webhooks = vec![ 
        Webhook { url: "http://api.example.com/user/1".to_string(), payload: "{}".to_string() },
        Webhook { url: "http://api.example.com/fail/2".to_string(), payload: "{}".to_string() },
        Webhook { url: "http://api.example.com/user/3".to_string(), payload: "{}".to_string() },
    ];

    for webhook in webhooks {
        let mut attempts = 0;
        const MAX_ATTEMPTS: u32 = 3;
        let mut success = false;

        while attempts < MAX_ATTEMPTS && !success {
            match webhook.dispatch() {
                Ok(()) => {
                    println!("Delivery successful after {} attempts.", attempts + 1);
                    success = true;
                }
                Err(e) => {
                    attempts += 1;
                    if attempts < MAX_ATTEMPTS {
                        let delay = Duration::from_millis(500 * (2u64.pow(attempts - 1) as u64));
                        println!("Attempt {} failed: {}. Retrying in {:?}", attempts, e, delay);
                        thread::sleep(delay);
                    } else {
                        eprintln!("Delivery permanently failed after {} attempts for {}", MAX_ATTEMPTS, webhook.url);
                    }
                }
            }
        }
    }
}

use std::sync::mpsc;
use std::thread;

struct ScanResult {
    file_path: String,
    is_secret: bool,
}

fn main() {
    let (tx, rx) = mpsc::channel();

    let files_to_scan = vec!["config.txt", "api_keys.json", "user_data.log"];

    for file in files_to_scan {
        let tx_clone = tx.clone();
        thread::spawn(move || {
            std::thread::sleep(std::time::Duration::from_millis(50));
            if file.contains("keys") {
                let result = ScanResult { 
                    file_path: file.to_string(), 
                    is_secret: true 
                };
                tx_clone.send(result).unwrap();
            } else if file.contains("user") {
                let result = ScanResult { 
                    file_path: file.to_string(), 
                    is_secret: false 
                };
                tx_clone.send(result).unwrap();
            }
        });
    }

    tx.send(ScanResult {
        file_path: "exit".to_string(),
        is_secret: false,
    }).unwrap();

    for received in rx {
        if received.file_path == "exit" {
            break;
        }
        println!("n=============================");
        println!("Scanning file: {}", received.file_path);
        if received.is_secret {
            println!("!!! DANGER !!! Secret found in this file.");
        } else {
            println!("Scan complete for {}. No obvious secrets detected.", received.file_path);
        }
    }
}
